# ── 2. Verificar si la URL está bloqueada ──
if is_blocked(url, config.get('blocked', [])):
    print(f"[BLOCKED] {url}")
    response = build_403_response(config)
    client_socket.sendall(response)
    client_socket.close()
    return

# ── 3. Extraer host, puerto y path ──
host, port, path = extract_host_from_url(url)

# ── 4. Construir la request a reenviar ──
new_request_line = f"{method} {path} HTTP/1.1"

new_headers = {}
skip_headers = {'proxy-connection', 'proxy-authorization', 'connection'}
for key, value in parsed_request['headers'].items():
    if key.lower() in skip_headers:
        continue
    new_headers[key] = value

if 'Host' not in new_headers:
    if port != 80:
        new_headers['Host'] = f"{host}:{port}"
    else:
        new_headers['Host'] = host

# Añadir X-ElQuePregunta
new_headers['X-ElQuePregunta'] = config.get('user', 'unknown')
new_headers['Connection'] = 'close'
